"use client";

import React, { useEffect, useRef, useState } from "react";
import { useTheme } from "../context/ThemeContext";
import styles from "./OrbsBackground.module.css";

// 3 premium orbs — cyan, blue, violet (no pink — keeps the 3D depth palette clean)
const ORB_CONFIG = [
    { color: "#22D3EE", radiusBase: 280, vx: 0.28, vy: 0.18, phase: 0 },       // Cyan
    { color: "#60A5FA", radiusBase: 320, vx: -0.22, vy: 0.26, phase: 2.1 },     // Blue
    { color: "#7C3AED", radiusBase: 300, vx: 0.18, vy: -0.24, phase: 4.2 },     // Violet
];

const OrbsBackground = () => {
    const canvasRef = useRef(null);
    const { theme } = useTheme();
    const [reducedMotion, setReducedMotion] = useState(false);
    const mouseRef = useRef({ x: 0, y: 0 });
    const orbsRef = useRef([]);

    // Reduced-motion preference
    useEffect(() => {
        const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
        setReducedMotion(mq.matches);
        const handler = (e) => setReducedMotion(e.matches);
        mq.addEventListener("change", handler);
        return () => mq.removeEventListener("change", handler);
    }, []);

    // Resize + mouse parallax + orb init
    useEffect(() => {
        const handleResize = () => {
            if (!canvasRef.current) return;
            const dpr = window.devicePixelRatio || 1;
            canvasRef.current.width = window.innerWidth * dpr;
            canvasRef.current.height = window.innerHeight * dpr;
        };

        const handleMouseMove = (e) => {
            // Max ~10px parallax shift
            mouseRef.current = {
                x: (e.clientX - window.innerWidth / 2) * 0.05,
                y: (e.clientY - window.innerHeight / 2) * 0.05,
            };
        };

        window.addEventListener("resize", handleResize);
        window.addEventListener("mousemove", handleMouseMove);
        handleResize();

        // Scatter orbs across viewport
        orbsRef.current = ORB_CONFIG.map((cfg) => ({
            ...cfg,
            x: Math.random() * window.innerWidth,
            y: Math.random() * window.innerHeight,
        }));

        return () => {
            window.removeEventListener("resize", handleResize);
            window.removeEventListener("mousemove", handleMouseMove);
        };
    }, []);

    // Animation loop
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        let animId;

        const render = (time) => {
            const dpr = window.devicePixelRatio || 1;
            const width = canvas.width / dpr;
            const height = canvas.height / dpr;

            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.save();
            ctx.scale(dpr, dpr);

            const isDark = theme === "dark";
            const orbOpacity = isDark ? 0.35 : 0.20;

            orbsRef.current.forEach((orb) => {
                // Drift
                if (!reducedMotion) {
                    orb.x += orb.vx;
                    orb.y += orb.vy;

                    // Wrap-around
                    if (orb.x < -orb.radiusBase) orb.x = width + orb.radiusBase;
                    if (orb.x > width + orb.radiusBase) orb.x = -orb.radiusBase;
                    if (orb.y < -orb.radiusBase) orb.y = height + orb.radiusBase;
                    if (orb.y > height + orb.radiusBase) orb.y = -orb.radiusBase;
                }

                // Breathing (scale pulse — slow and gentle)
                const breath = Math.sin(time * 0.00045 + orb.phase) * 28;
                const r = orb.radiusBase + breath;

                // Mouse parallax (max ~10px)
                const px = orb.x + mouseRef.current.x;
                const py = orb.y + mouseRef.current.y;

                // Radial gradient
                const grad = ctx.createRadialGradient(px, py, 0, px, py, r);
                grad.addColorStop(0, orb.color);
                grad.addColorStop(1, "transparent");

                ctx.globalAlpha = orbOpacity;
                ctx.fillStyle = grad;
                ctx.beginPath();
                ctx.arc(px, py, r, 0, Math.PI * 2);
                ctx.fill();
            });

            ctx.restore();
            animId = requestAnimationFrame(render);
        };

        animId = requestAnimationFrame(render);
        return () => cancelAnimationFrame(animId);
    }, [theme, reducedMotion]);

    return (
        <div className={styles.backgroundContainer}>
            <canvas ref={canvasRef} className={styles.canvas} />
            <div className={styles.vignette} />
            <div className={styles.noise} />
        </div>
    );
};

export default OrbsBackground;

